let index, indexed=ref(false);
let c=0;
const excludes={".gsync":1,".sync":1,".git":1};
export async function initDb(d){
  index = new Document({
      document: {
        store:true,
          id: "id",
          index: [/*{
            field: "path",
            tokenize: "exact",
          },*/
          /*"timestamp",*/
          {
            field:"content",
            tokenize: "forward",
          }]
        ,
      }
  });
  await addDir(d);
}
export async function addDir(d){
  await fs.promises.readdir(d);
  d=file(d);
  indexed.value=false;
  //search();
  d.watch((t,f,m)=>{
    //if(f.isDir())return ;
    for (let c of f.path().split("/")){
      if (excludes.hasOwnProperty(c)) return;
    }
    if (!f.exists()) return;
    add(f);
    //console.log("watch",f.path());
  });
  await _addAll(d);
  indexed.value=true;
  async function _addAll(d){
    //await fs.promises.stat(d.path());
  
    for (let f of await traverseHere(d)){
      await add(f);
      c++;if(c%50==0)await sleep(1);
    }
  }
  async function add(f){
    //await fs.promises.stat(f.path());
  
    const doc=await index.get(f.path());
    if(doc&&doc.timestamp===f.lastUpdate())return ;
    await index[doc?"update":"add"]({
      id:f.path(),
      timestamp: f.lastUpdate(),
      content: text(f)
    });
  }

} 
export async function traverseHere(f){
  const trs=(s)=>s.replace(/\/$/,"");
  const df=pNode.
    getDeviceManager().
    df().map(d=>
    trs(d.mountPoint));
  await fs.promises.readdir(f.path());
  return traverseNotIgnored(f.path());
  function* traverseNotIgnored(dir, ig = ignore()) {
    // also check .gitignore in subfolder
    const gitignore = path.join(dir, ".gitignore");
    let localIg = ig;
    if (fs.existsSync(gitignore)) {
      const rules = fs.readFileSync(gitignore, "utf8");
      localIg = ignore().add(ig).add(rules);
    }
    for (const name of fs.readdirSync(dir)) {
      const full = path.join(dir, name);
      if(excludes.hasOwnProperty(name)||
        df.includes(trs(full)))continue;
      const rel = name;
      if (localIg.ignores(rel)) continue;
      const st = fs.statSync(full);
      if (st.isDirectory()) {
        yield file(full);
        yield* traverseNotIgnored(full, localIg);
      } else {
        yield file(full);
      }
    }
  }
}

export async function traverseHereOLD(f){
  const trs=(s)=>s.replace(/\/$/,"");
  const df=pNode.
    getDeviceManager().
    df().map(d=>
    trs(d.mountPoint));
  await fs.promises.readdir(f.path());
  return f.recursive({
    includeDir:true,
    excludes(f){
      return excludes.hasOwnProperty(
        f.truncSep())||
        df.includes(trs(f.path()));
    },
  });
}

function text(f){
  if(f.isDir()){
    return f.ls().join("\n");
  }else return f.text();
}
function sortPath(paths, base) {
  if(!base)return paths;
  const baseDir = path.dirname(base);
  const i=paths.indexOf(base);
  if(i>=0)paths.splice(i,1);
  const inner=[];
  const outer=[];
  for(let path of paths){
    (path.startsWith(baseDir)?inner:outer).push(path);
  }
  //console.log("base",base,baseDir,inner);
  inner.sort((a,b)=>a.length-b.length);
  const so=base==baseDir? outer :sortPath(outer,baseDir);
  const res=[...inner,...so];
  res.unshift(base);
  return res;
}
